#include <bits/stdc++.h>
#define zrq0331
#define int long long
using namespace std;
int n;
int phi() {
	int ans = n;
	for (int i = 2; i * i <= n; i++) {
		if (n % i == 0) {
			int cnt = 0;
			while (n % i == 0) {
				n /= i;
				cnt++;
			}
			ans /= i;
			ans *= cnt * i - cnt + i;
		}
	}
	if (n > 1) {
		ans /= n;
		ans *= n + n - 1;
	}
	return ans;
}
signed main() {
	cin >> n;
	cout << phi();
	return 0;
}
